import{_ as a,a as e}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as d,o as r,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"حدود معدل الرفع للمستخدمين","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Safety/user-rate-limits.md","filePath":"ar-SA/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),o={name:"ar-SA/Safety/user-rate-limits.md"};function s(p,t,n,h,c,m){return r(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="حدود-معدل-الرفع-للمستخدمين" tabindex="-1">حدود معدل الرفع للمستخدمين <a class="header-anchor" href="#حدود-معدل-الرفع-للمستخدمين" aria-label="Permalink to &quot;حدود معدل الرفع للمستخدمين&quot;">​</a></h1><p>تتحكم user rate limits في عدد مرات رفع الملفات من الصفحة الرئيسية بواسطة المستخدمين العاديين أو الزوار. يساعد ذلك على منع إساءة استخدام صفحات الرفع العامة.</p><p>تؤثر هذه الميزة على رفع الصفحة الرئيسية فقط. رفع المسؤول والرفع عبر API Tokens لا يخضعان لهذه الحدود.</p><h2 id="أين-تضبطها؟" tabindex="-1">أين تضبطها؟ <a class="header-anchor" href="#أين-تضبطها؟" aria-label="Permalink to &quot;أين تضبطها؟&quot;">​</a></h2><p>افتح لوحة الإدارة، ثم انتقل إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+a+'" alt="إعدادات حدود معدل المستخدم" loading="lazy"></p><h2 id="تفعيل-الحدود" tabindex="-1">تفعيل الحدود <a class="header-anchor" href="#تفعيل-الحدود" aria-label="Permalink to &quot;تفعيل الحدود&quot;">​</a></h2><p>بعد تفعيل <code>Enable Rate Limits</code> يتتبع ImgBed الرفعات الأخيرة حسب IP الرافع.</p><p>القيم الافتراضية:</p><table tabindex="0"><thead><tr><th>الإعداد</th><th>الافتراضي</th><th>الوصف</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>المدة السابقة التي تُحسب ضمنها سجلات الرفع.</td></tr><tr><td>Max file count</td><td>20</td><td>الحد الأقصى لعدد الملفات داخل نافذة الكشف.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>الحد الأقصى لحجم ملف واحد.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>الحد الأقصى لإجمالي حجم الرفع داخل نافذة الكشف.</td></tr></tbody></table><p>مثلًا، مع نافذة 1.5 ساعة و20 ملفًا و20 MB لكل ملف و200 MB إجماليًا، تُحظر الرفعات من IP نفسه عند تجاوز أي حد مضبوط.</p><h2 id="استثناء-أنواع-الملفات" tabindex="-1">استثناء أنواع الملفات <a class="header-anchor" href="#استثناء-أنواع-الملفات" aria-label="Permalink to &quot;استثناء أنواع الملفات&quot;">​</a></h2><p>يقوم <code>Excluded upload file types</code> بمنع المستخدمين العاديين أو الزوار من رفع فئات ملفات محددة.</p><p>الفئات المتاحة:</p><table tabindex="0"><thead><tr><th>النوع</th><th>الوصف</th></tr></thead><tbody><tr><td>Images</td><td>ملفات الصور مثل jpg و png و webp و gif وما شابه</td></tr><tr><td>Videos</td><td>ملفات الفيديو مثل mp4 و webm و mov وما شابه</td></tr><tr><td>Audio</td><td>ملفات الصوت مثل mp3 و flac و wav وما شابه</td></tr><tr><td>Documents</td><td>ملفات المستندات مثل pdf و txt و md و docx وما شابه</td></tr><tr><td>Other</td><td>ملفات خارج الفئات السابقة، مثل zip و rar و exe و apk</td></tr></tbody></table><p>افتراضيًا لا تكون الفئة محددة، وهذا يعني أنها مسموحة.</p><p>النقر على فئة يبرزها، وهذا يعني أن ذلك النوع محظور.</p><p>إذا تم تحديد <code>Other</code> فسيُحظر رفع ملفات zip أو rar وسيُبلغ الزائر أن هذا النوع غير مدعوم.</p><h2 id="رسائل-الحظر" tabindex="-1">رسائل الحظر <a class="header-anchor" href="#رسائل-الحظر" aria-label="Permalink to &quot;رسائل الحظر&quot;">​</a></h2><p>عند تفعيل حد معين يرى المستخدم رسالة مناسبة:</p><p><img src="'+e+'" alt="رسالة الرفع المتكرر" loading="lazy"></p><table tabindex="0"><thead><tr><th>الحالة</th><th>معنى الرسالة</th></tr></thead><tbody><tr><td>ملف واحد كبير جدًا</td><td>الملف كبير جدًا ويجب ضغطه قبل الرفع.</td></tr><tr><td>نوع الملف محظور</td><td>هذا النوع غير مدعوم. أزله وحاول مرة أخرى.</td></tr><tr><td>الرفع متكرر جدًا</td><td>الرفعات الأخيرة كثيرة جدًا، ويظهر وقت إعادة المحاولة.</td></tr><tr><td>الحجم الإجمالي مرتفع جدًا</td><td>الحجم الإجمالي للرفعات الأخيرة مرتفع، ويظهر وقت إعادة المحاولة.</td></tr></tbody></table><h2 id="متى-تفعّلها؟" tabindex="-1">متى تفعّلها؟ <a class="header-anchor" href="#متى-تفعّلها؟" aria-label="Permalink to &quot;متى تفعّلها؟&quot;">​</a></h2><p>فعّل user rate limits إذا كانت صفحة الرفع الرئيسية متاحة للعامة.</p><p>أسباب شائعة:</p><ul><li>القلق من الرفع الجماعي عبر سكربتات.</li><li>الرغبة في الحد من رفع الملفات الكبيرة من الزوار.</li><li>السماح للمستخدمين العاديين برفع الصور فقط، وليس الأرشيفات أو ملفات التثبيت.</li><li>إبقاء الرفع العام متاحًا مع التحكم في استهلاك الموارد.</li></ul><p>إذا كان الموقع لك وحدك، أو كان الرفع مقتصرًا على المسؤولين، يمكنك تركها معطلة.</p>',28)])])}const f=d(o,[["render",s]]);export{_ as __pageData,f as default};
